arguments.file_text:
@page "/shipments"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipments</h1>

<div class="mb-3">
    <label for="statusFilter" class="form-label">Filter by Status:</label>
    <select id="statusFilter" class="form-select w-auto d-inline-block" @onchange="OnFilterChanged">
        <option value="">All</option>
        @foreach (var status in Enum.GetValues<ShipmentStatus>())
        {
            <option value="@status">@status</option>
        }
    </select>
</div>

@if (shipments is null)
{
    <p>Loading...</p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped Date</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in shipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>@shipment.Status</td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm d-inline-block w-auto"
                                @onchange="e => OnStatusSelected(shipment.Id, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status" selected="@(status == shipment.Status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string? currentFilter;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task OnFilterChanged(ChangeEventArgs e)
    {
        currentFilter = e.Value?.ToString();
        await LoadShipments();
    }

    private async Task OnStatusSelected(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(id, newStatus);
            await LoadShipments();
        }
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetShipmentsAsync(currentFilter);
    }
}

@page "/track"
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="mb-3">
    <label for="trackingNumber" class="form-label">Tracking Number:</label>
    <div class="input-group" style="max-width: 400px;">
        <input id="trackingNumber" type="text" class="form-control" @bind="trackingNumber" @bind:event="oninput"
               placeholder="Enter tracking number" @onkeydown="OnKeyDown" />
        <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
    </div>
</div>

@if (searched)
{
    @if (shipment is not null)
    {
        <div class="card mt-4" style="max-width: 500px;">
            <div class="card-header">
                <strong>Shipment @shipment.TrackingNumber</strong>
            </div>
            <div class="card-body">
                <p><strong>Status:</strong> @shipment.Status</p>
                <p><strong>Origin:</strong> @shipment.Origin</p>
                <p><strong>Destination:</strong> @shipment.Destination</p>
                <p><strong>Shipped Date:</strong> @shipment.ShippedDate.ToString("yyyy-MM-dd")</p>
                <p><strong>Estimated Delivery:</strong> @(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "N/A")</p>
                @if (shipment.ActualDelivery.HasValue)
                {
                    <p><strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("yyyy-MM-dd")</p>
                }
                <p><strong>Description:</strong> @shipment.Description</p>
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning mt-4" style="max-width: 500px;">
            No shipment found with tracking number "<strong>@searchedNumber</strong>".
        </div>
    }
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        searchedNumber = trackingNumber;
        shipment = await ShipmentService.GetByTrackingNumberAsync(trackingNumber);
        searched = true;
    }

    private async Task OnKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }
}

